using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private readonly ServiceRegistry _registry;

    public ServiceRegistryTests()
    {
        _registry = new ServiceRegistry();
    }

    [TestMethod]
    public void Register_WithValidService_CanBeResolved()
    {
        // Arrange
        var service = new FakeService();

        // Act
        _registry.Register<IFakeService>(service);
        var resolved = _registry.Resolve<IFakeService>();

        // Assert
        Assert.IsNotNull(resolved);
    }

    [TestMethod]
    public void Resolve_RegisteredService_ReturnsSameInstance()
    {
        // Arrange
        var service = new FakeService();
        _registry.Register<IFakeService>(service);

        // Act
        var resolved = _registry.Resolve<IFakeService>();

        // Assert
        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_UnregisteredService_ReturnsNull()
    {
        // Act
        var resolved = _registry.Resolve<IFakeService>();

        // Assert
        Assert.IsNull(resolved);
    }

    [TestMethod]
    public void Clear_AfterRegistration_RemovesAllServices()
    {
        // Arrange
        _registry.Register<IFakeService>(new FakeService());
        _registry.Register<IAnotherService>(new AnotherService());

        // Act
        _registry.Clear();

        // Assert
        Assert.IsNull(_registry.Resolve<IFakeService>());
        Assert.IsNull(_registry.Resolve<IAnotherService>());
        Assert.IsEmpty(_registry.GetAll());
    }

    [TestMethod]
    public void Remove_RegisteredService_MakesItUnresolvable()
    {
        // Arrange
        _registry.Register<IFakeService>(new FakeService());

        // Act
        _registry.Remove<IFakeService>();

        // Assert
        Assert.IsNull(_registry.Resolve<IFakeService>());
    }

    private interface IFakeService;
    private interface IAnotherService;
    private sealed class FakeService : IFakeService;
    private sealed class AnotherService : IAnotherService;
}

